    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE & OPTION GENERATOR ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17
    ];

    // 1. Create Answer Pools for Distractors
    const globalAnswerPool: string[] = [];
    const categoryAnswerPools: Record<string, string[]> = {};

    sources.forEach(q => {
        const cat = q.category || 'General';
        if (!categoryAnswerPools[cat]) categoryAnswerPools[cat] = [];

        // Add valid short answers to pools to be used as distractors
        if (q.answerText && q.answerText.length < 100 && !q.answerText.toLowerCase().includes('all of the above') && !q.answerText.toLowerCase().includes('none of the above')) {
            categoryAnswerPools[cat].push(q.answerText);
            globalAnswerPool.push(q.answerText);
        }
    });

    // 2. Process Every Question
    sources.forEach(q => {
        if (!seenIds.has(q.id)) {
            let finalOptions = q.options ? [...q.options] : [];

            // AUTO-FIX: Generate options if missing or insufficient
            if (finalOptions.length < 2) {
                const cat = q.category || 'General';
                let pool = categoryAnswerPools[cat] || [];

                // If local chapter pool is too small, use the massive global pool
                if (pool.length < 5) { 
                    pool = [...pool, ...globalAnswerPool];
                }

                // Filter out the actual correct answer from the pool
                const validDistractors = pool.filter(a => a !== q.answerText);

                // Randomly select 3 distractors
                const randomDistractors = validDistractors
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];

                // Absolute Last Resort Fallback (if pools are empty)
                while (finalOptions.length < 4) {
                    const fallbacks = ["None of the above", "All of the above", "Structure not visible", "Not applicable"];
                    for (const fb of fallbacks) {
                        if (!finalOptions.includes(fb) && finalOptions.length < 4) {
                            finalOptions.push(fb);
                        }
                    }
                    if (finalOptions.length < 4) break; // prevent infinite loop
                }

                // Shuffle the newly generated options
                finalOptions.sort(() => 0.5 - Math.random());
            }

            // INTEGRITY CHECK: Ensure the correct answer is ALWAYS one of the options
            if (!finalOptions.includes(q.answerText)) {
                finalOptions[0] = q.answerText; // Force it in
                finalOptions.sort(() => 0.5 - Math.random()); // Reshuffle
            }

            uniqueQuestions.push({ ...q, options: finalOptions });
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, []);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         {/* Tidy Background */}
         <div className="absolute inset-0 bg-white"></div>
         <div className="absolute top-0 left-0 right-0 h-[60vh] bg-slate-50 rounded-b-[4rem] z-0"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-10 animate-fade-in">

            {/* Logo Section */}
            <div className="w-28 h-28 bg-white rounded-3xl shadow-xl shadow-slate-200 flex items-center justify-center relative cursor-pointer hover:scale-105 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-gradient-to-br from-rose-50 to-slate-50 rounded-3xl opacity-50"></div>
                <HeartPulse size={56} className="text-rose-500 relative z-10" strokeWidth={1.5} />
            </div>

            {/* Typography */}
            <div className="space-y-3">
               <span className="inline-block px-3 py-1 rounded-full bg-slate-100 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border border-slate-200">
                  Occupational Therapy
               </span>
               <h1 className="text-4xl md:text-5xl font-black text-slate-900 tracking-tight leading-tight font-display">
                  Anatomy <span className="text-rose-500">&</span><br/>Physiology
               </h1>
               <p className="text-slate-400 font-medium text-sm max-w-xs mx-auto leading-relaxed">
                  Professional study suite v.5.5
               </p>
            </div>

            {/* Action */}
            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-lg hover:bg-rose-600 hover:shadow-rose-200 transition-all transform active:scale-95 flex items-center justify-center gap-3"
                >
                     <span>Start Session</span>
                     <ChevronRight size={14} />
                </button>

                <div className="flex justify-center items-center gap-8 text-slate-300">
                    <div className="flex flex-col items-center gap-1.5">
                        <BookOpen size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">{allQuestions.length} Items</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1.5">
                        <Stethoscope size={18} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">Clinical</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden fixed inset-0 bg-slate-50">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full rounded-t-[2.5rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/50 bg-white/80 backdrop-blur-xl relative z-10 transition-all duration-700 ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <Flashcards data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <InteractiveAtlas data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-28 md:pb-0">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in">
                <QuestionList 
                  data={allQuestions}
                />
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

export default App;
